module accu(
    input clk, input rst_n, input [7:0] data_in, input valid_in,
    output reg valid_out, output reg [9:0] data_out
);
    reg [1:0] cnt;
    reg [7:0] data_in_reg [3:0];
    reg [9:0] sum;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            cnt <= 2'd0;
            sum <= 10'd0;
            valid_out <= 1'b0;
            data_out <= 10'd0;
        end
        else begin
            if(valid_in) begin
                data_in_reg[cnt] <= data_in;
                sum <= sum + data_in_reg[cnt];
                cnt <= cnt + 1;
                if(cnt == 2'd3) begin
                    cnt <= 2'd0;
                    sum <= 10'd0;
                    valid_out <= 1'b1;
                    data_out <= sum;
                end
                else begin
                    valid_out <= 1'b0;
                end
            end
            else begin
                cnt <= 2'd0;
                sum <= 10'd0;
                valid_out <= 1'b0;
                data_out <= 10'd0;
            end
        end
    end
endmodule
